const axios = require('axios');
const cron = require('node-cron');
const fs = require('fs').promises;

// Configuration - using environment variables from .env.test
const BASE_URL = 'http://localhost:3000';
const MONITORING_INTERVAL = process.env.MONITORING_INTERVAL || '5m'; // Default to every 5 minutes

// Log file path
const LOG_FILE = 'monitoring.log';

// Function to log messages
async function logMessage(message) {
    const timestamp = new Date().toISOString();
    const logEntry = `[${timestamp}] ${message}\n`;
    console.log(logEntry.trim());
    await fs.appendFile(LOG_FILE, logEntry);
}

// Function to check health endpoint
async function checkHealth() {
    try {
        const response = await axios.get(`${BASE_URL}/health`, { timeout: 5000 });
        await logMessage(`✅ HEALTH CHECK - Status: ${response.status}, Response: ${JSON.stringify(response.data)}`);
        return { healthy: true, status: response.status, data: response.data };
    } catch (error) {
        const errorMessage = error.response 
            ? `❌ HEALTH CHECK FAILED - Status: ${error.response.status}, Message: ${error.response.data}`
            : `❌ HEALTH CHECK FAILED - Error: ${error.message}`;
        await logMessage(errorMessage);
        return { healthy: false, error: error.message };
    }
}

// Function to check users endpoint
async function checkUsers() {
    try {
        const response = await axios.get(`${BASE_URL}/users`, { timeout: 5000 });
        await logMessage(`✅ USERS CHECK - Status: ${response.status}, Users count: ${response.data.length}`);
        return { success: true, status: response.status, data: response.data };
    } catch (error) {
        const errorMessage = error.response 
            ? `❌ USERS CHECK FAILED - Status: ${error.response.status}, Message: ${error.response.data}`
            : `❌ USERS CHECK FAILED - Error: ${error.message}`;
        await logMessage(errorMessage);
        return { success: false, error: error.message };
    }
}

// Main monitoring function
async function monitorEndpoints() {
    await logMessage('--- STARTING MONITORING CYCLE ---');

    // Check health endpoint
    const healthResult = await checkHealth();

    // Check users endpoint
    const usersResult = await checkUsers();

    // Overall status
    const isHealthy = healthResult.healthy && usersResult.success;
    const statusMessage = isHealthy ? '✅ ALL ENDPOINTS HEALTHY' : '⚠️ SOME ENDPOINTS UNHEALTHY';
    await logMessage(statusMessage);

    await logMessage('--- MONITORING CYCLE COMPLETE ---\n');
}

// Initialize monitoring
async function initMonitoring() {
    try {
        await logMessage('🚀 Starting monitoring service...');

        // Run immediately on startup
        await monitorEndpoints();

        // Schedule recurring checks
        cron.schedule(MONITORING_INTERVAL, monitorEndpoints);
        await logMessage(`⏰ Scheduled monitoring every ${MONITORING_INTERVAL}`);

    } catch (error) {
        console.error('Failed to initialize monitoring:', error);
        process.exit(1);
    }
}

// Handle graceful shutdown
process.on('SIGTERM', async () => {
    await logMessage('🛑 Received SIGTERM, shutting down gracefully...');
    process.exit(0);
});

process.on('SIGINT', async () => {
    await logMessage('🛑 Received SIGINT, shutting down gracefully...');
    process.exit(0);
});

// Export functions for potential use in other modules
module.exports = {
    monitorEndpoints,
    initMonitoring
};

// Start monitoring if this file is run directly
if (require.main === module) {
    initMonitoring();
}

